import{_ as i,o as a,c as t,ag as e}from"./chunks/framework.-Wrcbzkw.js";const g=JSON.parse('{"title":"常见的前端安全问题及其对策如下：","description":"","frontmatter":{},"headers":[],"relativePath":"basic/network/网络安全.md","filePath":"basic/network/网络安全.md","lastUpdated":1778838103000}'),n={name:"basic/network/网络安全.md"};function p(l,s,o,r,h,d){return a(),t("div",null,[...s[0]||(s[0]=[e('<h1 id="常见的前端安全问题及其对策如下" tabindex="-1">常见的前端安全问题及其对策如下： <a class="header-anchor" href="#常见的前端安全问题及其对策如下" aria-label="Permalink to &quot;常见的前端安全问题及其对策如下：&quot;">​</a></h1><h3 id="_1-跨站脚本攻击-xss" tabindex="-1">1. <strong>跨站脚本攻击（XSS）</strong> <a class="header-anchor" href="#_1-跨站脚本攻击-xss" aria-label="Permalink to &quot;1. **跨站脚本攻击（XSS）**&quot;">​</a></h3><p><strong>问题</strong>：攻击者在网页中注入恶意 JavaScript 代码，窃取用户数据或执行未授权操作。 <strong>对策</strong>：</p><ul><li><p>使用 <strong><code>v-html</code></strong> 或 <code>innerHTML</code> 时进行严格的输入过滤和转义。</p></li><li><p>在 Vue/React 等框架中，尽量避免使用 <code>dangerouslySetInnerHTML</code> 。</p></li><li><p>采用</p><p>内容安全策略（CSP）</p><p>限制脚本执行来源：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Security-Policy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default-src &#39;self&#39;; script-src &#39;self&#39; &#39;nonce-randomvalue&#39;;</span></span></code></pre></div></li><li><p>使用库 <strong>DOMPurify</strong> 进行输入清理。</p></li></ul><h3 id="_2-跨站请求伪造-csrf" tabindex="-1">2. <strong>跨站请求伪造（CSRF）</strong> <a class="header-anchor" href="#_2-跨站请求伪造-csrf" aria-label="Permalink to &quot;2. **跨站请求伪造（CSRF）**&quot;">​</a></h3><p><strong>问题</strong>：攻击者诱导用户访问恶意链接，利用用户的身份执行未授权的操作。 <strong>对策</strong>：</p><ul><li><p>采用 <strong>CSRF Token</strong>（例如在请求头中加入 <code>X-CSRF-TOKEN</code>）。</p></li><li><p>使用</p><p>SameSite Cookie</p><p>限制 Cookie 只在同源请求中发送：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Set-Cookie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sessionId=abc123; Secure; HttpOnly; SameSite=Strict</span></span></code></pre></div></li><li><p>结合 <strong>Referer</strong> 和 <strong>Origin 头</strong> 检测来源。</p></li></ul><h3 id="_3-点击劫持-clickjacking" tabindex="-1">3. <strong>点击劫持（Clickjacking）</strong> <a class="header-anchor" href="#_3-点击劫持-clickjacking" aria-label="Permalink to &quot;3. **点击劫持（Clickjacking）**&quot;">​</a></h3><p><strong>问题</strong>：攻击者使用透明 iframe 嵌套受害网站，诱导用户误点执行操作。 <strong>对策</strong>：</p><ul><li><p>禁用</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>iframe</span></span></code></pre></div><p>嵌套：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">X-Frame-Options</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DENY</span></span></code></pre></div></li><li><p>采用</p><p>CSP Frame Ancestors</p><p>限制页面可被嵌套的来源：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Security-Policy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frame-ancestors &#39;self&#39;;</span></span></code></pre></div></li></ul><h3 id="_4-数据泄露-sensitive-data-exposure" tabindex="-1">4. <strong>数据泄露（Sensitive Data Exposure）</strong> <a class="header-anchor" href="#_4-数据泄露-sensitive-data-exposure" aria-label="Permalink to &quot;4. **数据泄露（Sensitive Data Exposure）**&quot;">​</a></h3><p><strong>问题</strong>：敏感信息（如 Token、用户信息）暴露在前端，可能被攻击者窃取。 <strong>对策</strong>：</p><ul><li><p><strong>不要</strong> 在前端存储敏感数据，如 <code>localStorage</code>。</p></li><li><p>使用</p><p>HTTP Only</p><p>和</p><p>Secure</p><p>选项存储 Cookie：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Set-Cookie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth_token=abc123; Secure; HttpOnly</span></span></code></pre></div></li><li><p>采用 <strong>环境变量</strong> 隐藏 API Key（如 <code>.env</code> 文件）。</p></li></ul><h3 id="_5-不安全的-api-调用" tabindex="-1">5. <strong>不安全的 API 调用</strong> <a class="header-anchor" href="#_5-不安全的-api-调用" aria-label="Permalink to &quot;5. **不安全的 API 调用**&quot;">​</a></h3><p><strong>问题</strong>：API 接口未做权限控制，前端用户可以篡改请求参数绕过验证。 <strong>对策</strong>：</p><ul><li><p><strong>所有 API 必须进行后端权限校验</strong>（如 JWT、OAuth）。</p></li><li><p>在请求头中加入授权 Token：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Authorization</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Bearer &lt;token&gt;</span></span></code></pre></div></li><li><p>使用 <strong>速率限制（Rate Limit）</strong> 保护 API，防止暴力攻击。</p></li></ul><h3 id="_6-依赖项漏洞" tabindex="-1">6. <strong>依赖项漏洞</strong> <a class="header-anchor" href="#_6-依赖项漏洞" aria-label="Permalink to &quot;6. **依赖项漏洞**&quot;">​</a></h3><p><strong>问题</strong>：前端依赖的第三方库存在安全漏洞，可能导致攻击。 <strong>对策</strong>：</p><ul><li><p>使用</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm audit</span></span></code></pre></div><p>和</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yarn audit</span></span></code></pre></div><p>定期检查漏洞：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> audit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fix</span></span></code></pre></div></li><li><p>关注 <strong>CVE</strong>（Common Vulnerabilities and Exposures）公告，及时升级依赖。</p></li><li><p>避免使用弃用或长期未更新的库。</p></li></ul><h3 id="_7-代码注入-prototype-pollution、sql-注入" tabindex="-1">7. <strong>代码注入（Prototype Pollution、SQL 注入）</strong> <a class="header-anchor" href="#_7-代码注入-prototype-pollution、sql-注入" aria-label="Permalink to &quot;7. **代码注入（Prototype Pollution、SQL 注入）**&quot;">​</a></h3><p><strong>问题</strong>：攻击者利用原型污染或未经过滤的输入注入恶意代码。 <strong>对策</strong>：</p><ul><li><p>避免直接修改对象原型：</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">prototype</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.test </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hacked&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 禁止</span></span></code></pre></div></li><li><p>使用安全的库，如 <code>lodash.cloneDeep()</code> 处理对象。</p></li><li><p>对用户输入进行严格校验（如 <code>AJV</code> 库）。</p></li></ul><p>如果你在实际项目中遇到具体的前端安全问题，可以详细描述，我可以帮助你分析最佳的防护方案！ 🚀</p>',23)])])}const k=i(n,[["render",p]]);export{g as __pageData,k as default};
